// Calculate last Mon-Sun range + previous week for WoW comparison
const now = new Date();
const day = now.getUTCDay(); // 0=Sun, 1=Mon

// Last Monday = most recent Monday before today
// If today is Monday (1), last Monday is 7 days ago
const daysToLastMonday = day === 0 ? 6 : (day - 1) + 7;
const lastMonday = new Date(now);
lastMonday.setUTCDate(now.getUTCDate() - daysToLastMonday);
lastMonday.setUTCHours(0, 0, 0, 0);

const lastSunday = new Date(lastMonday);
lastSunday.setUTCDate(lastMonday.getUTCDate() + 6);
lastSunday.setUTCHours(23, 59, 59, 999);

// Previous week (Mon-Sun before last week)
const prevMonday = new Date(lastMonday);
prevMonday.setUTCDate(lastMonday.getUTCDate() - 7);
prevMonday.setUTCHours(0, 0, 0, 0);

const prevSunday = new Date(prevMonday);
prevSunday.setUTCDate(prevMonday.getUTCDate() + 6);
prevSunday.setUTCHours(23, 59, 59, 999);

const fmt = (d) => d.toISOString();
const fmtDate = (d) => d.toISOString().split('T')[0];

return [{ json: {
  thisWeekStart: fmt(lastMonday),
  thisWeekEnd: fmt(lastSunday),
  prevWeekStart: fmt(prevMonday),
  prevWeekEnd: fmt(prevSunday),
  thisWeekLabel: fmtDate(lastMonday) + ' to ' + fmtDate(lastSunday),
  prevWeekLabel: fmtDate(prevMonday) + ' to ' + fmtDate(prevSunday),
  reportDate: fmtDate(now)
} }];

// Build comprehensive revenue attribution report
const dates = $('Calculate Week Ranges').first().json;

const thisWeekRaw = $('Fetch Revenue This Week').first().json.body || [];
const prevWeekRaw = $('Fetch Revenue Previous Week').first().json.body || [];
const leadsRaw = $('Fetch Leads This Week').first().json.body || [];

const thisWeek = Array.isArray(thisWeekRaw) ? thisWeekRaw : [];
const prevWeek = Array.isArray(prevWeekRaw) ? prevWeekRaw : [];
const leads = Array.isArray(leadsRaw) ? leadsRaw : [];

// === Total Revenue ===
const thisRevenue = thisWeek.reduce((s, r) => s + (parseFloat(r.revenue) || 0), 0);
const prevRevenue = prevWeek.reduce((s, r) => s + (parseFloat(r.revenue) || 0), 0);
const revenueDiff = thisRevenue - prevRevenue;
const revenuePct = prevRevenue > 0 ? Math.round(((thisRevenue - prevRevenue) / prevRevenue) * 100) : (thisRevenue > 0 ? 100 : 0);

// === Leads ===
const totalLeads = leads.length;
const bookedLeads = leads.filter(l => l.status === 'booked' || l.status === 'completed').length;
const conversionRate = totalLeads > 0 ? Math.round((bookedLeads / totalLeads) * 10000) / 100 : 0;

// === Avg Job Value ===
const avgJobValue = thisWeek.length > 0 ? Math.round((thisRevenue / thisWeek.length) * 100) / 100 : 0;
const prevAvgJobValue = prevWeek.length > 0 ? Math.round((prevRevenue / prevWeek.length) * 100) / 100 : 0;
const avgJobDiff = Math.round((avgJobValue - prevAvgJobValue) * 100) / 100;

// === Revenue by Source ===
const bySource = {};
for (const r of thisWeek) {
  const src = (r.lead_source || 'unknown').toLowerCase();
  if (!bySource[src]) bySource[src] = { revenue: 0, jobs: 0 };
  bySource[src].revenue += parseFloat(r.revenue) || 0;
  bySource[src].jobs += 1;
}
const prevBySource = {};
for (const r of prevWeek) {
  const src = (r.lead_source || 'unknown').toLowerCase();
  if (!prevBySource[src]) prevBySource[src] = { revenue: 0, jobs: 0 };
  prevBySource[src].revenue += parseFloat(r.revenue) || 0;
  prevBySource[src].jobs += 1;
}

const allSources = [...new Set([...Object.keys(bySource), ...Object.keys(prevBySource)])];
const sourceTable = allSources
  .map(src => {
    const curr = bySource[src] || { revenue: 0, jobs: 0 };
    const prev = prevBySource[src] || { revenue: 0, jobs: 0 };
    const diff = curr.revenue - prev.revenue;
    const pct = prev.revenue > 0 ? Math.round(((curr.revenue - prev.revenue) / prev.revenue) * 100) : (curr.revenue > 0 ? 100 : 0);
    return { source: src, revenue: Math.round(curr.revenue * 100) / 100, jobs: curr.jobs, prevRevenue: Math.round(prev.revenue * 100) / 100, diff: Math.round(diff * 100) / 100, pct };
  })
  .sort((a, b) => b.revenue - a.revenue);

// === Revenue by Service ===
const byService = {};
for (const r of thisWeek) {
  const svc = (r.service_type || 'unknown').toLowerCase();
  if (!byService[svc]) byService[svc] = { revenue: 0, jobs: 0 };
  byService[svc].revenue += parseFloat(r.revenue) || 0;
  byService[svc].jobs += 1;
}
const prevByService = {};
for (const r of prevWeek) {
  const svc = (r.service_type || 'unknown').toLowerCase();
  if (!prevByService[svc]) prevByService[svc] = { revenue: 0, jobs: 0 };
  prevByService[svc].revenue += parseFloat(r.revenue) || 0;
  prevByService[svc].jobs += 1;
}

const allServices = [...new Set([...Object.keys(byService), ...Object.keys(prevByService)])];
const serviceTable = allServices
  .map(svc => {
    const curr = byService[svc] || { revenue: 0, jobs: 0 };
    const prev = prevByService[svc] || { revenue: 0, jobs: 0 };
    const diff = curr.revenue - prev.revenue;
    const pct = prev.revenue > 0 ? Math.round(((curr.revenue - prev.revenue) / prev.revenue) * 100) : (curr.revenue > 0 ? 100 : 0);
    return { service: svc, revenue: Math.round(curr.revenue * 100) / 100, jobs: curr.jobs, prevRevenue: Math.round(prev.revenue * 100) / 100, diff: Math.round(diff * 100) / 100, pct };
  })
  .sort((a, b) => b.revenue - a.revenue);

// === Highlights ===
const highlights = [];
if (thisRevenue > prevRevenue) highlights.push('Revenue up ' + (revenuePct >= 0 ? '+' : '') + revenuePct + '% week-over-week ($' + Math.round(thisRevenue).toLocaleString() + ' vs $' + Math.round(prevRevenue).toLocaleString() + ')');
if (thisRevenue < prevRevenue) highlights.push('Revenue down ' + revenuePct + '% week-over-week ($' + Math.round(thisRevenue).toLocaleString() + ' vs $' + Math.round(prevRevenue).toLocaleString() + ')');

const topSource = sourceTable.length > 0 ? sourceTable[0] : null;
if (topSource) highlights.push('Top source: ' + topSource.source + ' ($' + topSource.revenue.toLocaleString() + ', ' + topSource.jobs + ' jobs)');

const topService = serviceTable.length > 0 ? serviceTable[0] : null;
if (topService) highlights.push('Top service: ' + topService.service + ' ($' + topService.revenue.toLocaleString() + ', ' + topService.jobs + ' jobs)');

if (conversionRate > 0) highlights.push('Lead conversion rate: ' + conversionRate + '% (' + bookedLeads + '/' + totalLeads + ' leads)');

if (thisWeek.length === 0 && prevWeek.length === 0) highlights.push('No revenue data recorded for either week. Ensure TG-107 daily sync is running.');

// === Actions ===
const actions = [];
if (thisRevenue < prevRevenue && revenuePct < -20) actions.push('Revenue dropped >20% - review lead pipeline and job scheduling');
const lowSources = sourceTable.filter(s => s.diff < -100);
for (const ls of lowSources.slice(0, 2)) actions.push(ls.source + ' revenue dropped $' + Math.abs(ls.diff) + ' - investigate channel');
if (conversionRate < 30 && totalLeads > 5) actions.push('Conversion rate below 30% - review quote follow-up cadence');
if (actions.length === 0) actions.push('Revenue tracking healthy - no action needed');

// === Build TG-118 compatible report data ===
const sign = (v) => v >= 0 ? '+' : '';

const reportData = {
  report_title: 'Weekly Revenue Attribution',
  report_subtitle: dates.thisWeekLabel,
  sections: [
    {
      type: 'metrics',
      title: 'Revenue Overview',
      items: [
        { label: 'Total Revenue', value: '$' + Math.round(thisRevenue).toLocaleString(), change: sign(revenuePct) + revenuePct + '% WoW' },
        { label: 'Total Leads', value: totalLeads.toString(), change: '' },
        { label: 'Avg Job Value', value: '$' + avgJobValue.toLocaleString(), change: sign(avgJobDiff) + '$' + Math.abs(avgJobDiff) },
        { label: 'Conversion Rate', value: conversionRate + '%', change: '' }
      ]
    },
    {
      type: 'table',
      title: 'Revenue by Source',
      headers: ['Source', 'Revenue', 'Jobs', 'Prev Week', 'Change'],
      rows: sourceTable.map(s => [
        s.source,
        '$' + s.revenue.toLocaleString(),
        s.jobs.toString(),
        '$' + s.prevRevenue.toLocaleString(),
        (s.pct >= 0 ? '+' : '') + s.pct + '%'
      ])
    },
    {
      type: 'table',
      title: 'Revenue by Service',
      headers: ['Service', 'Revenue', 'Jobs', 'Prev Week', 'Change'],
      rows: serviceTable.map(s => [
        s.service,
        '$' + s.revenue.toLocaleString(),
        s.jobs.toString(),
        '$' + s.prevRevenue.toLocaleString(),
        (s.pct >= 0 ? '+' : '') + s.pct + '%'
      ])
    },
    {
      type: 'highlights',
      title: 'Key Highlights',
      items: highlights
    },
    {
      type: 'actions',
      title: 'Recommended Actions',
      items: actions
    }
  ]
};

return [{ json: {
  reportData,
  subject: 'TG Revenue Weekly: $' + Math.round(thisRevenue).toLocaleString() + ' (' + sign(revenuePct) + revenuePct + '% WoW)',
  storePayload: {
    report_type: 'revenue_attribution',
    report_date: dates.reportDate,
    report_data: {
      week_label: dates.thisWeekLabel,
      total_revenue: Math.round(thisRevenue * 100) / 100,
      prev_revenue: Math.round(prevRevenue * 100) / 100,
      revenue_change_pct: revenuePct,
      total_leads: totalLeads,
      conversion_rate: conversionRate,
      avg_job_value: avgJobValue,
      jobs_count: thisWeek.length,
      by_source: sourceTable,
      by_service: serviceTable,
      highlights,
      actions
    }
  }
} }];

// Log completion
const data = $('Build Report Data').first().json;
return [{ json: {
  status: 'complete',
  report_type: 'revenue_attribution',
  report_date: data.storePayload.report_date,
  total_revenue: data.storePayload.report_data.total_revenue,
  revenue_change_pct: data.storePayload.report_data.revenue_change_pct,
  completedAt: new Date().toISOString()
} }];
